// Parse custom video request
const input = $input.all()[0].json;

// Validate required fields
if (!input.title || !input.script) {
  return {
    error: 'Missing required fields: title and script',
    required: ['title', 'script'],
    received: Object.keys(input)
  };
}

// Set defaults
return {
  title: input.title,
  script: input.script,
  description: input.description || `Custom video: ${input.title}`,
  tags: input.tags || ['custom', 'news'],
  visualStyle: input.visualStyle || 'mixed', // stock, ai, web, mixed
  thumbnailStyle: input.thumbnailStyle || 'viral-news',
  voice: input.voice || 'nick',
  music: input.music !== false, // default true
  lowerThirds: input.lowerThirds !== false, // default true
  videoId: 'custom_' + Date.now(),
  timestamp: new Date().toISOString()
};

// Build video manifest
const input = $input.all()[0].json;
const llmResponse = $input.all()[1]?.json;

// Parse segments from LLM or create default
let segments = [];
try {
  const content = llmResponse.choices?.[0]?.message?.content || llmResponse.content;
  const parsed = JSON.parse(content.match(/{[\s\S]*}/)[0]);
  segments = parsed.segments || parsed;
} catch (e) {
  // Default segmentation
  const scriptParts = input.script.split('\n\n');
  segments = scriptParts.map((part, i) => ({
    type: i === 0 ? 'intro' : i === scriptParts.length - 1 ? 'conclusion' : 'content',
    script: part,
    visual: 'mixed',
    lowerThird: i === 0 ? input.title : ''
  }));
}

return {
  ...input,
  segments: segments.map((s, i) => ({
    ...s,
    segmentIndex: i,
    totalSegments: segments.length
  }))
};

// Split segments for processing
const data = $input.all()[0].json;
return data.segments.map(segment => ({
  ...data,
  ...segment,
  segmentScript: segment.script || segment.text
}));

// Aggregate results
const all = $input.all();
const first = all[0].json;

return {
  output: `/files/output/${first.videoId}.mp4`,
  segments: all.map(item => ({
    type: item.json.type || 'content',
    audio: `/files/audio/${first.videoId}_${item.json.segmentIndex}.mp3`,
    visual: item.json.visualPath || `/files/images/custom_${first.videoId}_${item.json.segmentIndex}.jpg`,
    lowerThird: item.json.lowerThird || '',
    title: item.json.type === 'intro' ? first.title : undefined
  })),
  thumbnail: {
    output: `/files/images/${first.videoId}_thumb.jpg`,
    title: first.title,
    style: first.thumbnailStyle
  },
  youtubeTitle: first.title,
  description: first.description,
  tags: first.tags,
  videoId: first.videoId
};

return {
  success: true,
  message: 'Custom video created successfully',
  videoId: $input.all()[0].json.videoId,
  youtubeTitle: $input.all()[0].json.youtubeTitle
};

return {
  success: false,
  error: $input.all()[0].json.error || 'Invalid request',
  required: ['title', 'script']
};
